import { SelectOption } from '../models/form-field.model';

/**
 * Type guard to check if a value is null or undefined
 * @param value The value to check
 * @returns true if the value is null or undefined
 */
export function isNullOrUndefined<T>(
  value: T | null | undefined,
): value is null | undefined {
  return value === null || value === undefined;
}

/**
 * Type guard to check if a value is defined (not null and not undefined)
 * @param value The value to check
 * @returns true if the value is defined
 */
export function isDefined<T>(value: T | null | undefined): value is T {
  return value !== null && value !== undefined;
}

/**
 * Type guard to check if a value is a string
 * @param value The value to check
 * @returns true if the value is a string
 */
export function isString(value: unknown): value is string {
  return typeof value === 'string';
}

/**
 * Type guard to check if a value is a number
 * @param value The value to check
 * @returns true if the value is a number
 */
export function isNumber(value: unknown): value is number {
  return typeof value === 'number' && !isNaN(value);
}

/**
 * Type guard to check if a value is a boolean
 * @param value The value to check
 * @returns true if the value is a boolean
 */
export function isBoolean(value: unknown): value is boolean {
  return typeof value === 'boolean';
}

/**
 * Type guard to check if a value is an array
 * @param value The value to check
 * @returns true if the value is an array
 */
export function isArray<T>(value: unknown): value is T[] {
  return Array.isArray(value);
}

/**
 * Type guard to check if a value is an object (not null, not array)
 * @param value The value to check
 * @returns true if the value is an object
 */
export function isObject(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null && !Array.isArray(value);
}

/**
 * Type guard to check if a value is a valid Date
 * @param value The value to check
 * @returns true if the value is a valid Date
 */
export function isValidDate(value: unknown): value is Date {
  return value instanceof Date && !isNaN(value.getTime());
}

/**
 * Type guard to check if a value is empty (null, undefined, empty string, empty array, empty object)
 * @param value The value to check
 * @returns true if the value is empty
 */
export function isEmpty(value: unknown): boolean {
  if (isNullOrUndefined(value)) return true;
  if (isString(value)) return value.trim().length === 0;
  if (isArray(value)) return value.length === 0;
  if (isObject(value)) return Object.keys(value).length === 0;
  return false;
}

/**
 * Type guard to check if a value matches a specific enum
 * @param enumType The enum to check against
 * @param value The value to check
 * @returns true if the value exists in the enum
 */
export function isEnumValue<T extends Record<string, string | number>>(
  enumType: T,
  value: unknown,
): value is T[keyof T] {
  return Object.values(enumType).includes(value as T[keyof T]);
}

/**
 * Type guard to check if all properties of an object are defined
 * @param obj The object to check
 * @returns true if all properties are defined
 */
export function hasRequiredProperties<T extends object>(obj: T): boolean {
  return Object.values(obj).every((value) => isDefined(value));
}

/**
 * Type guard to check if value has a specific property
 * @param value The value to check
 * @param prop The property to check for
 * @returns true if the value has the specified property
 */
export function hasProperty<K extends string>(
  value: unknown,
  prop: K,
): value is Record<K, unknown> {
  return isObject(value) && prop in value;
}

/**
 * Type guard to check if a value is a function with specific signature
 * @template T The return type of the function
 * @template Args The argument types of the function
 * @param value The value to check
 * @returns true if the value is a function matching the signature
 */
export function isFunction<T = unknown, Args extends unknown[] = unknown[]>(
  value: unknown,
): value is (...args: Args) => T {
  return typeof value === 'function';
}

/**
 * Type guard to check if a value is a SelectOption
 * @param value The value to check
 * @returns true if the value is a SelectOption
 */
export function isSelectOption(value: unknown): value is SelectOption {
  return (
    isObject(value) &&
    hasProperty(value, 'label') &&
    hasProperty(value, 'value') &&
    isString(value['label'])
  );
}

/**
 * Deep comparison of two objects or values
 * Performs a recursive comparison of nested objects and arrays
 *
 * @param obj1 First value to compare
 * @param obj2 Second value to compare
 * @returns true if the objects are deeply equal
 */
export function isDeepEqual<T>(obj1: T, obj2: T): boolean {
  // Handle primitives and referential equality
  if (obj1 === obj2) return true;

  // If either is null/undefined but not both (we already checked === above)
  if (isNullOrUndefined(obj1) || isNullOrUndefined(obj2)) return false;

  // Check if they're the same type
  const type1 = typeof obj1;
  const type2 = typeof obj2;
  if (type1 !== type2) return false;

  // Handle dates
  if (isValidDate(obj1) && isValidDate(obj2)) {
    return obj1.getTime() === obj2.getTime();
  }

  // Handle arrays
  if (isArray(obj1) && isArray(obj2)) {
    if (obj1.length !== obj2.length) return false;

    return obj1.every((item, index) => isDeepEqual(item, obj2[index]));
  }

  // Handle objects
  if (isObject(obj1) && isObject(obj2)) {
    const keys1 = Object.keys(obj1);
    const keys2 = Object.keys(obj2);

    if (keys1.length !== keys2.length) return false;

    // Check that all keys in obj1 exist in obj2 and have equal values
    return keys1.every((key) => {
      return (
        hasProperty(obj2, key) &&
        isDeepEqual(obj1[key as keyof T], obj2[key as keyof T])
      );
    });
  }

  // For any other type, if they're not equal by === they're not equal
  return false;
}
