import { Injectable } from '@angular/core';
import { environment } from '../../../environments/environment';
import { isString } from '../../shared/utils';

@Injectable({
  providedIn: 'root',
})
export class ApiUrlService {
  private apiUrl: string = environment.apiUrls[0]; // Default fallback
  private cachedUrlObj: URL | null = null;

  constructor() {
    const savedUrl = localStorage.getItem('apiUrl');
    this.setApiUrl(isString(savedUrl) ? savedUrl : this.apiUrl);
  }

  setApiUrl(url: string) {
    if (!url.trim()) throw new Error('Empty API URL');
    try {
      const urlObj = new URL(url);
      this.cachedUrlObj = urlObj;
      this.apiUrl = url;
      localStorage.setItem('apiUrl', url);
    } catch (error) {
      this.cachedUrlObj = null;
      throw error;
    }
  }

  getCurrentApiUrl(): string {
    return this.apiUrl;
  }

  getUrlObject(): URL {
    if (!this.cachedUrlObj) {
      throw new Error(
        'No valid API URL configured. Please check your settings.',
      );
    }
    return this.cachedUrlObj;
  }
}
