import { isNullOrUndefined } from './type-guards';

/**
 * Type for any object with string keys (safer than Record<string, any>)
 */
export interface JsonObject {
  [key: string]: JsonValue;
}

/**
 * Type for any valid JSON value
 */
export type JsonValue =
  | string
  | number
  | boolean
  | null
  | JsonObject
  | JsonValue[];

/**
 * Gets a nested property from an object using a dot-notation path
 *
 * @param source The source object to get the property from
 * @param path A dot-notation path to the property (e.g. "user.address.street")
 * @param defaultValue Value to return if the property doesn't exist
 * @returns The property value or the default value
 */
export function getNestedProperty<T>(
  source: JsonObject | null | undefined,
  path: string,
  defaultValue?: T,
): T | undefined {
  if (isNullOrUndefined(source) || !path) {
    return defaultValue;
  }

  const keys = path.split('.');
  let current: unknown = source;

  for (const key of keys) {
    if (current === null || current === undefined) {
      return defaultValue;
    }
    if (typeof current !== 'object') {
      return defaultValue;
    }
    // Type assertion here is safer than before
    current = (current as Record<string, unknown>)[key];
  }

  return current === undefined ? defaultValue : (current as T);
}

/**
 * Sets a nested property on an object using a dot-notation path
 *
 * @param target The target object to set the property on
 * @param path A dot-notation path to the property (e.g. "user.address.street")
 * @param value The value to set
 * @returns The modified target object
 */
export function setNestedProperty<T extends JsonObject, V extends JsonValue>(
  target: T,
  path: string,
  value: V,
): T | null {
  if (isNullOrUndefined(target) || !path) {
    return null;
  }

  const keys = path.split('.');
  let current: Record<string, unknown> = target;

  // Traverse the path except for the last key
  for (let i = 0; i < keys.length - 1; i++) {
    const key = keys[i];

    // If the current location is not an object, create one
    if (
      current[key] === undefined ||
      current[key] === null ||
      typeof current[key] !== 'object'
    ) {
      current[key] = {} as JsonObject;
    }

    // Safe assertion since we ensure it's an object above
    current = current[key] as Record<string, unknown>;
  }

  // Set the value at the final key
  const lastKey = keys[keys.length - 1];
  current[lastKey] = value;

  return target;
}

/**
 * Checks if a nested property exists in an object using a dot-notation path
 *
 * @param source The source object to check
 * @param path A dot-notation path to the property (e.g. "user.address.street")
 * @returns True if the property exists, false otherwise
 */
export function hasNestedProperty(
  source: JsonObject | null | undefined,
  path: string,
): boolean {
  if (isNullOrUndefined(source) || !path) {
    return false;
  }

  const keys = path.split('.');
  let current: unknown = source;

  for (const key of keys) {
    if (
      current === null ||
      current === undefined ||
      typeof current !== 'object'
    ) {
      return false;
    }

    // Using a safer check with Object.hasOwn
    if (!Object.hasOwn(current, key)) {
      return false;
    }

    current = (current as Record<string, unknown>)[key];
  }

  return true;
}

/**
 * Deletes a nested property from an object using a dot-notation path
 *
 * @param target The target object to delete the property from
 * @param path A dot-notation path to the property (e.g. "user.address.street")
 * @returns True if the property was deleted, false otherwise
 */
export function deleteNestedProperty<T extends JsonObject>(
  target: T,
  path: string,
): boolean {
  if (isNullOrUndefined(target) || !path) {
    return false;
  }

  const keys = path.split('.');
  let current: unknown = target;

  // Navigate to the parent of the property to delete
  for (let i = 0; i < keys.length - 1; i++) {
    const key = keys[i];
    if (
      current === null ||
      current === undefined ||
      typeof current !== 'object' ||
      !Object.hasOwn(current, key)
    ) {
      return false;
    }
    current = (current as Record<string, unknown>)[key];
  }

  // Delete the property
  const lastKey = keys[keys.length - 1];
  if (
    current === null ||
    current === undefined ||
    typeof current !== 'object' ||
    !Object.hasOwn(current, lastKey)
  ) {
    return false;
  }

  return delete (current as Record<string, unknown>)[lastKey];
}

/**
 * Merges a value into an object at a specified nested path
 *
 * @param target The target object to merge into
 * @param path A dot-notation path where the value should be merged (e.g. "user.address")
 * @param value The value to merge at the specified path
 * @returns The modified target object
 */
export function mergeAtPath<T extends JsonObject, V extends JsonObject>(
  target: T,
  path: string,
  value: V,
): T {
  if (isNullOrUndefined(target) || !path) {
    return target;
  }

  const existingValue = getNestedProperty<JsonObject>(target, path, {});
  const merged = { ...existingValue, ...value };
  return setNestedProperty(target, path, merged) ?? target;
}

/**
 * Converts an enum object to an array of select option values with properly formatted labels
 *
 * @param enumObj The enum object to convert
 * @param formatLabel Optional custom formatter for labels (defaults to auto-spacing)
 * @returns Array of {label, value} pairs suitable for dropdowns
 */
export function enumToSelectOptionValues<T>(
  enumObj: Record<string, T>,
  formatLabel?: (key: string) => string,
): { label: string; value: T }[] {
  return Object.entries(enumObj)
    .filter(([key]) => isNaN(Number(key))) // Filter out numeric keys
    .map(([key, value]) => ({
      label: formatLabel ? formatLabel(key) : formatEnumKey(key),
      value,
    }));
}

/**
 * Formats an enum key by adding spaces between words and capitalizing first letters
 * Works with both PascalCase (DigitalInput) and snake_case (digital_input)
 *
 * @param key The enum key to format
 * @returns Formatted label with proper spacing and capitalization
 */
function formatEnumKey(key: string): string {
  // If key contains underscores, use them for splitting
  if (key.includes('_')) {
    return key
      .split('_')
      .map((word) => capitalizeFirstLetter(word))
      .join(' ');
  }

  // Handle PascalCase or camelCase by inserting spaces before capital letters
  // Transform: "DigitalInput" -> "Digital Input"
  return (
    key
      // Add space before capital letters but not at the beginning
      .replace(/([A-Z])/g, ' $1')
      .trim() // Remove any leading space
      .split(' ')
      .map((word) => capitalizeFirstLetter(word))
      .join(' ')
  );
}

/**
 * Capitalizes just the first letter of a string
 */
function capitalizeFirstLetter(str: string): string {
  if (!str) return '';
  return str.charAt(0).toUpperCase() + str.slice(1).toLowerCase();
}
