import { HttpClient } from '@angular/common/http';
import { Injectable, inject } from '@angular/core';
import { Observable } from 'rxjs';
import { AuthResponse } from '../models/auth.model';
import { ApiUrlService } from './api-url.service';
import { isNullOrUndefined } from '../../shared/utils';

@Injectable({
  providedIn: 'root',
})
export class AuthService {
  private readonly http = inject(HttpClient);
  private readonly apiUrlService = inject(ApiUrlService);

  login(username: string, password: string): Observable<AuthResponse> {
    const currentApiUrl = this.apiUrlService.getCurrentApiUrl();
    return this.http.post<AuthResponse>(`${currentApiUrl}/auth/signin`, {
      username,
      password,
    });
  }

  refreshToken(refreshToken: string): Observable<AuthResponse> {
    const currentApiUrl = this.apiUrlService.getCurrentApiUrl();
    return this.http.post<AuthResponse>(`${currentApiUrl}/auth/refresh`, {
      refreshToken,
    });
  }

  isAuthenticated(): boolean {
    const expiry = localStorage.getItem('tokenExpiry');
    if (isNullOrUndefined(expiry)) {
      return false;
    }
    return Date.now() < parseInt(expiry, 10);
  }
}
