import { isDefined, isNullOrUndefined } from '../../shared/utils';

export const APP_FEATURE_FLAGS = 'fleet-ui-v2';
export const BACKEND_FEATURE_FLAGS = 'fleet-backend-v2';

export type FeatureType =
  | 'checkbox'
  | 'toggle'
  | 'dropdown'
  | 'number'
  | 'text'
  | 'checklist'
  | 'memo'
  | 'list';

export interface FormBuilderKeyValue {
  key: string | boolean | null; // Allow null for 'Inherit'
  value: string;
  fields?: FormBuilderField[];
}

export interface FormBuilderField {
  id: string;
  title: string;
  type: string;
  required?: boolean;
  value?: string | number;
  defaultValue?: string | number;
  values?: FormBuilderKeyValue[];
  valueLookup?: string;
  min?: number;
  max?: number;
  hint?: string;
  description?: string;
}

export interface FeatureSection {
  id: string;
  title: string;
  icon: string;
  fields: FormBuilderField[];
  addEnabledToggle: (id: string, defaultValue: boolean) => FeatureSection;
  addCombo: (
    id: string,
    values: FormBuilderKeyValue[],
    defaultValue: string | null, // Allow null for 'Inherit'
  ) => FeatureSection;
  addNumber: (
    id: string,
    min: number,
    max: number,
    defaultValue: number | null, // Allow null for 'Inherit'
  ) => FeatureSection;
  addCheckList: (
    id: string,
    lookupKey: string,
    defaultValue: string[],
  ) => FeatureSection;
  addMemo: (id: string, defaultValue: string[]) => FeatureSection;
  addText: (
    id: string,
    defaultValue: string,
    required: boolean,
  ) => FeatureSection;
  addList: (id: string) => FeatureSection;
}

export type FeatureSections = Record<string, FeatureSection>;
export type FeatureValue = boolean | string | number | null;

