// Feature sections for UI building
export const AppFeatures: Record<string, FeatureSection> = {};

// Flattened defaults for storage
export const AppFeatureFlagDefaults: Record<string, FeatureValue> = {};

export class AppFeatureSection implements FeatureSection {
  id: string;
  icon = '';
  title = '';
  fields: FormBuilderField[] = [];
  subfields: FormBuilderField[] = [];

  constructor(
    public page: string,
    defaultState: boolean,
  ) {
    this.id = page;
    this.title =
      AppFeatureTranslations[page.toUpperCase()]?.['TITLE'] ??
      page.toUpperCase();
    this.icon = PAGE_ICONS[page.split('-')[1]] ?? 'cog';

    this.fields.push({
      id: this.page + '-enabled',
      title: 'Page',
      type: 'dropdown',
      required: true,
      values: [
        { key: null, value: 'Inherit' }, // Use null for 'Inherit'
        { key: true, value: 'Enabled', fields: this.subfields },
        { key: false, value: 'Disabled' },
      ],
    });

    this.addDefault('enabled', defaultState);
    AppFeatures[this.page] = this;
  }

  private addDefault(
    id: string,
    defaultValue: boolean | string | number | string[] | null,
  ): void {
    // Convert array to string for storage if needed, handle null
    let separator = ',';
    if (id === 'tabs') {
      separator = '\n';
    }
    const valueToStore = Array.isArray(defaultValue)
      ? defaultValue.join(separator)
      : defaultValue;
    AppFeatureFlagDefaults[`${this.page}-${id}`] = valueToStore;
  }

  addEnabledToggle(id: string, defaultValue: boolean): FeatureSection {
    this.addDefault(id, defaultValue);
    this.subfields.push({
      id: `${this.page}-${id}`,
      title:
        AppFeatureTranslations[this.page.toUpperCase()]?.[id.toUpperCase()] ??
        id.toUpperCase(),
      type: 'dropdown',
      required: true,
      values: [
        { key: null, value: 'Inherit' },
        { key: true, value: 'Enabled' },
        { key: false, value: 'Disabled' },
      ],
      hint:
        AppFeatureTranslations[this.page.toUpperCase()]?.[
          `${id.toUpperCase()}-DESC`
        ] ?? '',
    });
    return this;
  }

  addCombo(
    id: string,
    values: FormBuilderKeyValue[],
    defaultValue: string | null,
  ): FeatureSection {
    this.addDefault(id, defaultValue);
    this.subfields.push({
      id: `${this.page}-${id}`,
      title:
        AppFeatureTranslations[this.page.toUpperCase()]?.[id.toUpperCase()] ??
        id.toUpperCase(),
      type: 'dropdown',
      required: true,
      values: [{ key: null, value: 'Inherit' }, ...values], // Add Inherit option
      hint:
        AppFeatureTranslations[this.page.toUpperCase()]?.[
          `${id.toUpperCase()}-DESC`
        ] ?? '',
    });
    return this;
  }

  addNumber(
    id: string,
    min: number,
    max: number,
    defaultValue: number | null,
  ): FeatureSection {
    this.addDefault(id, defaultValue);
    this.subfields.push({
      id: `${this.page}-${id}`,
      title:
        AppFeatureTranslations[this.page.toUpperCase()]?.[id.toUpperCase()] ??
        id.toUpperCase(),
      type: 'number',
      required: false, // Numbers are often optional overrides
      min: min,
      max: max,
      hint:
        AppFeatureTranslations[this.page.toUpperCase()]?.[
          `${id.toUpperCase()}-DESC`
        ] ?? '',
    });
    return this;
  }

  addCheckList(
    id: string,
    lookupKey: string,
    defaultValue: string[],
  ): FeatureSection {
    this.addDefault(id, defaultValue); // Store as comma-separated string
    this.subfields.push({
      id: `${this.page}-${id}`,
      title:
        AppFeatureTranslations[this.page.toUpperCase()]?.[id.toUpperCase()] ??
        id.toUpperCase(),
      type: 'checklist',
      required: false,
      values: [],
      valueLookup: lookupKey,
      hint:
        AppFeatureTranslations[this.page.toUpperCase()]?.[
          `${id.toUpperCase()}-DESC`
        ] ?? '',
    });
    return this;
  }

  addMemo(id: string, defaultValue: string[]): FeatureSection {
    this.addDefault(id, defaultValue); // Store as newline-separated string
    this.subfields.push({
      id: `${this.page}-${id}`,
      title:
        AppFeatureTranslations[this.page.toUpperCase()]?.[id.toUpperCase()] ??
        id.toUpperCase(),
      type: 'memo',
      required: false,
      hint:
        AppFeatureTranslations[this.page.toUpperCase()]?.[
          `${id.toUpperCase()}-DESC`
        ] ?? '',
    });
    return this;
  }

  addText(id: string, defaultValue: string, required: boolean): FeatureSection {
    this.addDefault(id, defaultValue);
    this.subfields.push({
      id: `${this.page}-${id}`,
      title:
        AppFeatureTranslations[this.page.toUpperCase()]?.[id.toUpperCase()] ??
        id.toUpperCase(),
      type: 'text',
      required: required,
      hint:
        AppFeatureTranslations[this.page.toUpperCase()]?.[
          `${id.toUpperCase()}-DESC`
        ] ?? '',
    });
    return this;
  }

  addList(id: string): FeatureSection {
    this.addDefault(id, ''); // Default for list is usually an empty string representing empty list
    this.subfields.push({
      id: `${this.page}-${id}`,
      title:
        AppFeatureTranslations[this.page.toUpperCase()]?.[id.toUpperCase()] ??
        id.toUpperCase(),
      type: 'list',
      required: false,
      hint:
        AppFeatureTranslations[this.page.toUpperCase()]?.[
          `${id.toUpperCase()}-DESC`
        ] ?? '',
    });
    return this;
  }
}

