/**
 * Creates a feature section for app UI features
 */
export function createFeature(
  pageId: string,
  defaultState: boolean,
): AppFeatureSection {
  return new AppFeatureSection('page-' + pageId, defaultState);
}

/**
 * Creates a feature section for backend features
 */
export function createBackendFeature(id: string): BackendFeatureSection {
  return new BackendFeatureSection(id);
}

/**
 * Returns backend feature defaults with proper owner type filtering
 */
export function getBackendFeatureDefaults(ownerType: string): {
  bucket: string;
  sections: Record<string, BackendFeatureSection>;
  defaults: Record<string, FeatureValue>;
} {
  const result: {
    bucket: string;
    sections: Record<string, BackendFeatureSection>;
    defaults: Record<string, FeatureValue>;
  } = {
    bucket: BACKEND_FEATURE_FLAGS,
    sections: {},
    defaults: {},
  };

  Object.keys(BackendFeatureDefaults).forEach((name) => {
    const sectionConfig = BackendFeatureDefaults[name];
    if (
      isNullOrUndefined(sectionConfig) || // Type guard
      !('_only' in sectionConfig) ||
      (Array.isArray(sectionConfig._only) &&
        sectionConfig._only.includes(ownerType))
    ) {
      const section = new BackendFeatureSection(name);
      Object.keys(sectionConfig).forEach((featureKey) => {
        if (featureKey !== '_only') {
          const featureValue = sectionConfig[featureKey];

          // Handle top-level enabled toggles (e.g., geocoding.roadspeed.enabled)
          if (
            typeof featureValue === 'object' &&
            featureValue !== null &&
            'enabled' in featureValue &&
            typeof featureValue.enabled === 'boolean'
          ) {
            section.addEnabledToggle(
              `${featureKey}-enabled`,
              featureValue.enabled,
            );
          }

          // Handle nested properties (like numbers, strings, etc. within the feature object)
          if (
            isDefined(featureValue) &&
            typeof featureValue === 'object' &&
            !Array.isArray(featureValue) &&
            featureValue !== null
          ) {
            Object.keys(featureValue).forEach((propKey) => {
              const propValue = (featureValue as Record<string, unknown>)[
                propKey
              ];
              if (propKey !== 'enabled') {
                // Add specific handlers based on type if needed
                if (typeof propValue === 'number') {
                  section.addNumber(
                    `${featureKey}-${propKey}`,
                    0, // Default min, adjust if needed
                    propValue * 10 || 1000, // Default max (10x default or 1000), adjust if needed
                    propValue,
                  );
                } else if (typeof propValue === 'string') {
                  // Example: Add text field if it's a string property
                  // section.addText(`${featureKey}-${propKey}`, propValue, false);
                }
                // Add more handlers for other types (boolean, array) if necessary
              }
            });
          } else if (typeof featureValue === 'number') {
            // Handle top-level number properties (e.g., api.rateLimit)
            section.addNumber(
              featureKey,
              0,
              featureValue * 10 || 1000,
              featureValue,
            );
          }
          // Add handlers for top-level boolean, string, array properties if needed
        }
      });

      if (section.fields.length > 0) {
        result.sections[name] = section;
        result.defaults = {
          ...result.defaults,
          ...section.defaults,
        };
      }
    }
  });

  return result;
}

// Helper function to initialize show toggles
function initializeShowToggles(
  section: AppFeatureSection,
  showConfig: PageShowConfig,
): void {
  Object.keys(showConfig).forEach((featureKey) => {
    const feature = featureKey as keyof PageShowConfig;
    const defaultValue = showConfig[feature];
    if (typeof defaultValue === 'boolean') {
      section.addEnabledToggle(`show-${feature}`, defaultValue);
    }
  });
}

// Helper function to initialize basic properties
function initializeBasicProperties(
  section: AppFeatureSection,
  pageConfig: Partial<PageConfig>,
): void {
  if (pageConfig.group !== undefined) {
    section.addText('group', pageConfig.group, false);
  }
  if (isDefined(pageConfig.order)) {
    section.addNumber('order', 0, 1000, pageConfig.order);
  }
  if (isDefined(pageConfig.name)) {
    section.addText('name', pageConfig.name, false);
  }
  if (isDefined(pageConfig.icon)) {
    section.addText('icon', pageConfig.icon, false);
  }
}

// Helper function to initialize advanced properties
function initializeAdvancedProperties(
  section: AppFeatureSection,
  pageConfig: Partial<PageConfig>,
): void {
  if (isDefined(pageConfig.pageSize)) {
    section.addNumber('pageSize', 5, 1000, pageConfig.pageSize);
  }
  if (isDefined(pageConfig.layout)) {
    section.addCombo(
      'layout',
      [
        { key: 'advanced', value: 'Advanced' },
        { key: 'basic', value: 'Basic' },
      ],
      pageConfig.layout,
    );
  }
  if (isDefined(pageConfig.maxDuration)) {
    section.addNumber('maxDuration', 1, 600, pageConfig.maxDuration);
  }
  if (isDefined(pageConfig.feedLoadLimit)) {
    section.addNumber('feedLoadLimit', 30, 500, pageConfig.feedLoadLimit);
  }
}

// Helper function to initialize list properties
function initializeListProperties(
  section: AppFeatureSection,
  pageConfig: Partial<PageConfig>,
): void {
  if (isDefined(pageConfig.actions)) {
    section.addCheckList(
      'actions',
      'alert-actions',
      pageConfig.actions.split(',').filter((a) => a),
    );
  }
  if (isDefined(pageConfig.reports)) {
    section.addCheckList(
      'reports',
      'reports',
      pageConfig.reports.split(',').filter((r) => r),
    );
  }
  if (isDefined(pageConfig.tabs)) {
    section.addList('tabs');
  }
  if (isDefined(pageConfig.availableAssetTypes)) {
    section.addCheckList(
      'availableAssetTypes',
      'assetTypes',
      pageConfig.availableAssetTypes.split(',').filter((t) => t),
    );
  }
  if (isDefined(pageConfig.customPanels)) {
    section.addList('customPanels');
  }
}

// This function is called during app initialization to set up feature defaults
export function initializeFeatureDefaults(): void {
  Object.keys(AppFeatureDefaults.page).forEach((name) => {
    const pageConfig = AppFeatureDefaults.page[name];
    if (isNullOrUndefined(pageConfig)) return;

    const section = createFeature(name, pageConfig.enabled ?? false);

    if (pageConfig.show) {
      initializeShowToggles(section, pageConfig.show);
    }

    initializeBasicProperties(section, pageConfig);
    initializeAdvancedProperties(section, pageConfig);
    initializeListProperties(section, pageConfig);

    if (isDefined(pageConfig.dateLimitOverride)) {
      section.addEnabledToggle(
        'dateLimitOverride',
        pageConfig.dateLimitOverride,
      );
    }
    if (isDefined(pageConfig.supportUrl)) {
      section.addText('supportUrl', pageConfig.supportUrl, false);
    }
  });
}

