import { ActivatedRouteSnapshot, CanActivateFn, Route } from '@angular/router';
import { isDefined } from './type-guards';
import { Type } from '@angular/core';

export function getAllRouteParams(
  route: ActivatedRouteSnapshot,
): Record<string, string> {
  let currentRoute: ActivatedRouteSnapshot | null = route;
  const params: Record<string, string> = {};
  while (isDefined(currentRoute)) {
    for (const key of currentRoute.paramMap.keys) {
      params[key] = currentRoute.paramMap.get(key) as string;
    }
    currentRoute = currentRoute.parent;
  }
  return params;
}

/**
 * Creates a pair of routes for a guarded grid feature:
 * 1. Base path with guard and optional component
 * 2. Grid sub-route for the specified grid component
 *
 * @param basePath - The base URL path segment
 * @param guard - The route guard to apply to the base path
 * @param gridComponent - Component to render for the grid view
 * @param baseComponent - Optional component to render at the base path
 * @param gridPath - Optional path for the grid route (defaults to 'grid/:type')
 * @returns Array of routes for the feature
 */
export function createGuardedGridRoute(
  basePath: string,
  guard: CanActivateFn,
  gridComponent: Type<unknown>,
  baseComponent?: Type<unknown>,
  gridPath = 'grid/:type',
): Route[] {
  return [
    {
      path: basePath,
      canActivate: [guard],
      component: baseComponent || undefined,
      children: [], // Keep empty children array to allow for future sub components
    },
    {
      path: `${basePath}/${gridPath}`,
      component: gridComponent,
    },
    {
      path: `${basePath}/${gridPath}/:entityType/:entityId`,
      component: gridComponent,
    },
  ];
}
